+    let over_budget = decomposition.over_budget_phases();
+    assert_eq!(over_budget.len(), 1);
+    assert_eq!(over_budget[0].phase, QueryPhase::FastVectorSearch);
+    assert_eq!(over_budget[0].overshoot_us(), 2_600);
